mapper.select:
SELECT b.*, c.name as category_name, c.`desc` as category_desc
FROM books b LEFT JOIN categories c ON b.categoryId = c.id
WHERE b.id = #{id}

SELECT b.* FROM books b LEFT JOIN categories c ON b.categoryId = c.id
WHERE 1=1
AND (b.title LIKE CONCAT('%', #{search}, '%') OR b.author LIKE CONCAT('%', #{search}, '%') OR b.isbn LIKE CONCAT('%', #{search}, '%'))
AND b.categoryId = #{categoryId}
AND b.year >= #{yearMin}
AND b.year <= #{yearMax}
AND b.language = #{language}
AND b.id IN (SELECT bookId FROM book_items WHERE campus = #{campus})
ORDER BY

  b.year DESC
  b.title ASC
  b.created_at DESC

SELECT COUNT(*) FROM books b LEFT JOIN categories c ON b.categoryId = c.id
WHERE 1=1
AND (b.title LIKE CONCAT('%', #{search}, '%') OR b.author LIKE CONCAT('%', #{search}, '%') OR b.isbn LIKE CONCAT('%', #{search}, '%'))
AND b.categoryId = #{categoryId}
AND b.year >= #{yearMin}
AND b.year <= #{yearMax}
AND b.language = #{language}

mapper.update:
UPDATE books SET updated_at=NOW()
, isbn=#{isbn}
, title=#{title}
, author=#{author}
, publisher=#{publisher}
, year=#{year}
, total=#{total}
, location=#{location}
, cover=#{cover}
, `desc`=#{desc}
, clcNumber=#{clcNumber}
, physicalDesc=#{physicalDesc}
, language=#{language}
, country=#{country}
, categoryId=#{categoryId}
WHERE id=#{id}
